   356→     * If any of the above are not met, the leader node is returned.
   357→     *
   358→     * @param partition {@link TopicPartition} for which we want to fetch data
   359→     * @param leaderReplica {@link Node} for the leader of the given partition
   360→     * @param currentTimeMs Current time in milliseconds; used to determine if we're within the optional lease window
   361→     * @return Replica {@link Node node} from which to request the data
   362→     * @see SubscriptionState#preferredReadReplica
   363→     * @see SubscriptionState#updatePreferredReadReplica
   364→     */
   365→    Node selectReadReplica(final TopicPartition partition, final Node leaderReplica, final long currentTimeMs) {
   366→        Optional<Integer> nodeId = subscriptions.preferredReadReplica(partition, currentTimeMs);
   367→
   368→        if (nodeId.isPresent()) {
   369→            Optional<Node> node = nodeId.flatMap(id -> metadata.fetch().nodeIfOnline(partition, id));
   370→            if (node.isPresent()) {
   371→                return node.get();
   372→            } else {
   373→                log.trace("Not fetching from {} for partition {} since it is marked offline or is missing from our metadata," +
   374→                        " using the leader instead.", nodeId, partition);
   375→                // Note that this condition may happen due to stale metadata, so we clear preferred replica and
   376→                // refresh metadata.
   377→                requestMetadataUpdate(metadata, subscriptions, partition);
   378→                return leaderReplica;
   379→            }
   380→        } else {
   381→            return leaderReplica;
   382→        }
   383→    }
   384→
   385→    protected Map<Node, FetchSessionHandler.FetchRequestData> prepareCloseFetchSessionRequests() {
   386→        final Cluster cluster = metadata.fetch();
   387→        Map<Node, FetchSessionHandler.Builder> fetchable = new HashMap<>();
