   175→     * {@link NetworkClient#send(ClientRequest, long) enqueues/sends it, and adds the {@link RequestFuture callback}
   176→     * for the response.
   177→     *
   178→     * @param fetchRequests  {@link Map} of {@link Node nodes} to their
   179→     *                       {@link FetchSessionHandler.FetchRequestData request data}
   180→     * @param successHandler {@link ResponseHandler Handler for successful responses}
   181→     * @param errorHandler   {@link ResponseHandler Handler for failure responses}
   182→     * @return List of {@link RequestFuture callbacks}
   183→     */
   184→    private List<RequestFuture<ClientResponse>> sendFetchesInternal(Map<Node, FetchSessionHandler.FetchRequestData> fetchRequests,
   185→                                                                    ResponseHandler<ClientResponse> successHandler,
   186→                                                                    ResponseHandler<Throwable> errorHandler) {
   187→        final List<RequestFuture<ClientResponse>> requestFutures = new ArrayList<>();
   188→
   189→        for (Map.Entry<Node, FetchSessionHandler.FetchRequestData> entry : fetchRequests.entrySet()) {
   190→            final Node fetchTarget = entry.getKey();
   191→            final FetchSessionHandler.FetchRequestData data = entry.getValue();
   192→            final FetchRequest.Builder request = createFetchRequest(fetchTarget, data);
   193→            final RequestFuture<ClientResponse> responseFuture = client.send(fetchTarget, request);
   194→
   195→            responseFuture.addListener(new RequestFutureListener<>() {
   196→                @Override
   197→                public void onSuccess(ClientResponse resp) {
